sql:
SELECT name, npatients
FROM regions
WHERE npatients = (
  SELECT MAX(npatients)
  FROM regions
);

SELECT name 
FROM regions 
WHERE population = (SELECT MAX(population) FROM regions);

SELECT region_id, name
FROM regions
WHERE ncurrentpatients > (SELECT AVG(ncurrentpatients) FROM regions);

SELECT name, npatients
FROM regions
WHERE npatients = (SELECT MAX(npatients) FROM regions);

SELECT region_id, AVG(ndeaths) AS average_deaths
FROM regions
GROUP BY region_id;

external_knowledge:
- 'High data quality score' refers to scores of 0.9 or above;
- 'Test rate per person' is calculated as the rounded number of tests divided by the population;
- 'Updated every day' indicates daily data frequency.

sql:
SELECT DISTINCT regions.name 
FROM regions 
INNER JOIN data_sources ON regions.region_id = data_sources.region_id;

SELECT AVG(npatients) AS average_patients_per_region
FROM regions
WHERE npatients > 100000;
